constraints_manifest.dsl:
@input = $config.prompt
@constraints_raw = generate(
  $config.prompt_constraints_strict,
  worker:analyzer,
  input:@input,
  think:false,
  continue:true,
  temperature:0.2,
  max_tokens:1024
)

@constraints = parse_sections(
  @constraints_raw,
  entities:"ENTITIES:",
  axioms:"AXIOMS:",
  hypotheses:"HYPOTHESES:"
)

answer_constraints_verdict.dsl:
@input = $config.prompt
@chat = "session"
@table_text = ""

set_text(@chat, user, @input)
set_text(@chat, assistant, "<think>\n\n</think>\n\n")

on @input -> @draft = generate(
  @chat,
  mode:continue,
  continue:true,
  temperature:0.6,
  max_tokens:2048
)

on @input -> @constraints_raw = generate(
  $config.prompt_constraints_strict,
  worker:analyzer,
  input:@input,
  think:false,
  continue:true,
  temperature:0.2,
  max_tokens:1024
)

on @constraints_raw -> @constraints = parse_sections(
  @constraints_raw,
  entities:"ENTITIES:",
  axioms:"AXIOMS:",
  hypotheses:"HYPOTHESES:"
)

on @constraints -> @answers_header = table_header(@constraints.entities, @constraints.axioms)

on @draft, @answers_header -> append_text(@chat, assistant, @draft.answer)
on @draft, @answers_header -> append_text(@chat, assistant, "\n\n")
on @draft, @answers_header -> append_text(@chat, assistant, @answers_header.content)
on @draft, @answers_header -> append_text(@chat, assistant, "\n| 1 |")

on @draft, @answers_header -> append_text(@table_text, content, @answers_header.content)
on @draft, @answers_header -> append_text(@table_text, content, "\n| 1 |")

on @draft, @answers_header -> @table_chunk = generate(
  @chat,
  mode:continue,
  continue:false,
  temperature:0.1,
  max_tokens:1024,
  stop:"\n\n\n"
)

on @table_chunk -> append_text(@chat, assistant, @table_chunk.answer)
on @table_chunk -> append_text(@table_text, content, @table_chunk.answer)
on @table_chunk -> @parsed = parse_table(@table_text)
on @parsed -> @row_total = row_count(@parsed)
on @row_total -> @need_more = lt(@row_total, $config.target_rows)

loop(while:@need_more, max_iters:$config.max_table_iters) {
  @table_chunk = generate(
    @chat,
    mode:continue,
    continue:false,
    temperature:0.1,
    max_tokens:1024,
    stop:"\n\n\n"
  )
  append_text(@chat, assistant, @table_chunk.answer)
  append_text(@table_text, content, @table_chunk.answer)
  @parsed = parse_table(@table_text)
  @row_total = row_count(@parsed)
  @need_more = lt(@row_total, $config.target_rows)
}

@accepted = accepted_list(@table_text, checks:@constraints.axioms)
@accepted_rows = filter_rows(@table_text, where:all_yes, checks:@constraints.axioms)
@rejected = reject_reasons(@table_text, checks:@constraints.axioms)

hypothesis_verdict.dsl:
@input = $config.prompt
@constraints_raw = generate(
  $config.prompt_constraints_strict,
  worker:analyzer,
  input:@input,
  think:false,
  continue:true,
  temperature:0.2,
  max_tokens:1024
)

@constraints = parse_sections(
  @constraints_raw,
  entities:"ENTITIES:",
  axioms:"AXIOMS:",
  hypotheses:"HYPOTHESES:"
)

@hyp_header = table_header(@constraints.hypotheses)
@hyp_table_text = ""

append_text(@hyp_table_text, content, @hyp_header.content)
append_text(@hyp_table_text, content, "\n| 1 |")

@hyp_chat = "session"
set_text(@hyp_chat, user, @input)
set_text(@hyp_chat, assistant, @hyp_header.content)
append_text(@hyp_chat, assistant, "\n| 1 |")

@hyp_chunk = generate(
  @hyp_chat,
  mode:continue,
  continue:false,
  temperature:0.1,
  max_tokens:768,
  stop:"\n\n\n"
)

append_text(@hyp_chat, assistant, @hyp_chunk.answer)
append_text(@hyp_table_text, content, @hyp_chunk.answer)

@hyp_parsed = parse_table(@hyp_table_text)
@hyp_rows = row_count(@hyp_parsed)
@hyp_need_more = lt(@hyp_rows, 2)

loop(while:@hyp_need_more, max_iters:$config.max_table_iters) {
  @hyp_chunk = generate(
    @hyp_chat,
    mode:continue,
    continue:false,
    temperature:0.1,
    max_tokens:768,
    stop:"\n\n\n"
  )
  append_text(@hyp_chat, assistant, @hyp_chunk.answer)
  append_text(@hyp_table_text, content, @hyp_chunk.answer)
  @hyp_parsed = parse_table(@hyp_table_text)
  @hyp_rows = row_count(@hyp_parsed)
  @hyp_need_more = lt(@hyp_rows, 2)
}

constraints_manifest_tail.dsl:
@input = $config.prompt
@tail_log = ""

@entities_seed_raw = generate(
  $config.prompt_constraints_entities_seed,
  worker:generator,
  input:@input,
  think:false,
  continue:false,
  temperature:0.2,
  max_tokens:384,
  format:instruct
)
append_text(@tail_log, content, "entities.seed\n")
append_text(@tail_log, content, @entities_seed_raw.answer)
append_text(@tail_log, content, "\n\n")
@entities_seed = split(@entities_seed_raw)
@entities_seed_json = join(@entities_seed, sep:", ", prefix:"[", suffix:"]")

@entities_tail_raw = generate(
  $config.prompt_constraints_entities_tail,
  worker:analyzer,
  input:@input,
  known:@entities_seed_json,
  think:false,
  continue:false,
  temperature:0.1,
  max_tokens:256,
  format:instruct
)
append_text(@tail_log, content, "entities.tail\n")
append_text(@tail_log, content, @entities_tail_raw.answer)
append_text(@tail_log, content, "\n\n")
@entities_tail = split(@entities_tail_raw)
@entities_all0 = concat(@entities_seed, @entities_tail)
@entities_all = unique(@entities_all0)
@entities_all_json = join(@entities_all, sep:", ", prefix:"[", suffix:"]")

@axioms_seed_raw = generate(
  $config.prompt_constraints_axioms_seed,
  worker:generator,
  input:@input,
  entities:@entities_all_json,
  think:false,
  continue:false,
  temperature:0.2,
  max_tokens:512,
  format:instruct
)
append_text(@tail_log, content, "axioms.seed\n")
append_text(@tail_log, content, @axioms_seed_raw.answer)
append_text(@tail_log, content, "\n\n")
@axioms_seed = split(@axioms_seed_raw)
@axioms_seed_json = join(@axioms_seed, sep:", ", prefix:"[", suffix:"]")

@axioms_tail_raw = generate(
  $config.prompt_constraints_axioms_tail,
  worker:analyzer,
  input:@input,
  entities:@entities_all_json,
  known:@axioms_seed_json,
  think:false,
  continue:false,
  temperature:0.1,
  max_tokens:320,
  format:instruct
)
append_text(@tail_log, content, "axioms.tail\n")
append_text(@tail_log, content, @axioms_tail_raw.answer)
append_text(@tail_log, content, "\n\n")
@axioms_tail = split(@axioms_tail_raw)
@axioms_all0 = concat(@axioms_seed, @axioms_tail)
@axioms_all = unique(@axioms_all0)
@axioms_all_json = join(@axioms_all, sep:", ", prefix:"[", suffix:"]")

@hypotheses_seed_raw = generate(
  $config.prompt_constraints_hypotheses_seed,
  worker:generator,
  input:@input,
  entities:@entities_all_json,
  axioms:@axioms_all_json,
  think:false,
  continue:false,
  temperature:0.2,
  max_tokens:384,
  format:instruct
)
append_text(@tail_log, content, "hypotheses.seed\n")
append_text(@tail_log, content, @hypotheses_seed_raw.answer)
append_text(@tail_log, content, "\n\n")
@hypotheses_seed = split(@hypotheses_seed_raw)
@hypotheses_seed_json = join(@hypotheses_seed, sep:", ", prefix:"[", suffix:"]")

@hypotheses_tail_raw = generate(
  $config.prompt_constraints_hypotheses_tail,
  worker:analyzer,
  input:@input,
  entities:@entities_all_json,
  axioms:@axioms_all_json,
  known:@hypotheses_seed_json,
  think:false,
  continue:false,
  temperature:0.1,
  max_tokens:256,
  format:instruct
)
append_text(@tail_log, content, "hypotheses.tail\n")
append_text(@tail_log, content, @hypotheses_tail_raw.answer)
append_text(@tail_log, content, "\n\n")
@hypotheses_tail = split(@hypotheses_tail_raw)
@hypotheses_all0 = concat(@hypotheses_seed, @hypotheses_tail)
@hypotheses_all = unique(@hypotheses_all0)
@hypotheses_all_json = join(@hypotheses_all, sep:", ", prefix:"[", suffix:"]")

@constraints_tail = ""
append_text(@constraints_tail, content, "ENTITIES:\n")
append_text(@constraints_tail, content, @entities_all_json.content)
append_text(@constraints_tail, content, "\n\nAXIOMS:\n")
append_text(@constraints_tail, content, @axioms_all_json.content)
append_text(@constraints_tail, content, "\n\nHYPOTHESES:\n")
append_text(@constraints_tail, content, @hypotheses_all_json.content)

@constraints = parse_sections(
  @constraints_tail,
  entities:"ENTITIES:",
  axioms:"AXIOMS:",
  hypotheses:"HYPOTHESES:"
)
